INSERT INTO profile_scenario_responses (id, profile_id, scenario_id, response, reasoning_chain, emotional_arc, confidence, generation_run_id) VALUES
('a3146e98-2083-45d7-87dc-d75f2a7c4007', '423fa2a4-e189-4b26-a9d2-ddfe6e83b6b3', 'ed314526-b17f-4dd2-bf47-84ad1ee7a6ab', 'Faced with this, the individual chases the move in real time, adjusting size on gut feel as the price ticks, and true to form is swayed by which number comes first, not just what the numbers mean.', 'Keeps every option notionally open as long as possible, even at the cost of the best ones expiring first. This time the variable is money moving in real time.', 'A sharp initial spike of dread, resolving into guilt absorption — that lingers and colors the aftermath long after the moment passes.', 0.44, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('41cc0fc9-edf2-43fe-921d-1062784d9c61', '26fb33be-d10e-4820-a146-b8629d83ce85', '110388b3-95e0-4e98-9d16-c76789404d32', 'Faced with this, this person flips the position on a hunch mid-session without waiting for confirmation, and true to form would not buy back what it already owns at the price it would sell it for.', 'Looks for a reason the decision belongs to someone else, or to a later date, before considering it directly. The numbers on the screen are the only feedback that matters here.', 'A sharp initial spike of dread, resolving into fomo buying — that gets relived and replayed long after it stops being useful.', 0.47, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('18c93b7d-ba3b-47b7-857a-80b08bbf1ec4', 'ff299e63-c1b6-43d4-a382-2155ab83b343', 'cbd05e75-9567-418c-ab4b-2369323703ee', 'Faced with this, this type takes the contrarian side deliberately, willing to be early and wrong before being right, and true to form cannot see the gap in its own knowledge from inside the gap.', 'Skips the formal weighing entirely — the answer arrives whole, and the reasoning is reconstructed only if someone asks for it. This time the variable is money moving in real time.', 'A momentary tightening before the response settles, resolving into fomo buying — that dissolves quickly once the ambiguity clears.', 0.59, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('106db248-ff63-442f-9d2b-30307553f449', '3dc873fe-8d02-4945-9db7-ed91e080d1cd', '20b64055-25ea-4008-a58e-9ea56b7f39d0', 'Faced with this, this type treats the moment as one more data point for a system, not an exception to react to, and true to form underestimates how often an obviously right call turns out wrong.', 'Lays out the options explicitly, assigns each a rough expected value, and picks the one that survives the numbers — distrusting any impulse that cannot be written down. Price action does not care which argument feels more convincing.', 'The faintest tightening, gone as soon as it is noticed, resolving into relief capitulation — that is essentially forgotten by the next decision.', 0.89, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('bdb4dfb1-b789-4c4a-a05e-a1693fe4a441', '4eb82e24-9614-4725-9c58-f93cab27ca4d', 'ed314526-b17f-4dd2-bf47-84ad1ee7a6ab', 'Faced with this, this type reacts to the headline before confirming it, then scrambles to justify the trade after, and true to form overweights the vivid story over the boring statistic every time.', 'Keeps every option notionally open as long as possible, even at the cost of the best ones expiring first. Price action does not care which argument feels more convincing.', 'An immediate jolt of alarm, resolving into fomo buying — that lingers and colors the aftermath long after the moment passes.', 0.53, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b4ec2515-4173-4a68-943e-c77f753646fe', 'c9f41dd5-41d9-4662-9971-48286669e78d', 'a733be1d-23c6-4d27-96ab-d283dbdc5622', 'Faced with this, the individual presses the position further, treating the volatility itself as the opportunity, and true to form jumps into whatever everyone else already seems to be winning at.', 'Feels the decision settle before it is fully articulated, and moves on that settling rather than waiting for certainty. The numbers on the screen are the only feedback that matters here.', 'A rush of adrenaline that narrows focus fast, resolving into anxious spiral — that leaves a residue of vigilance well past the event itself.', 0.52, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('e7a23d14-e831-4f85-b3cb-86b543e7f170', '304e788c-7d68-41ab-8f54-058a2a8eee53', '2a514bf5-beed-4b0b-9ca6-3e8b570e8fb6', 'Faced with this, this type flips the position on a hunch mid-session without waiting for confirmation, and true to form delays checking the number it most needs to check.', 'Searches first for a way to not decide — a delay, a deferral, a partial step — and only acts when forced. This time the variable is money moving in real time.', 'A sharp initial spike of dread, resolving into panic selling — that leaves a residue of vigilance well past the event itself.', 0.53, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('1a6beca7-7f23-41be-be82-372b0b76710e', '896973dc-1100-411f-9bf5-b8c5b818fc12', '6733ee11-e30c-4c63-980f-45f0a80d916d', 'Faced with this, this type acts on the first strong feeling, hitting the button before the reasoning fully forms, and true to form feels parting with something as a bigger loss than its market value explains.', 'Reframes inaction as patience, and patience as strategy, for as long as the situation allows. Price action does not care which argument feels more convincing.', 'An instant lurch in the stomach, resolving into anxious spiral — that leaves a residue of vigilance well past the event itself.', 0.53, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b7039fcb-711f-4679-98fd-fd9cf0ba01cb', 'dae12403-de8e-4f66-be21-1fdfe92ce500', 'a6c95379-5434-41ab-9654-1e3a43d4d67e', 'Faced with this, this type presses the position further, treating the volatility itself as the opportunity, and true to form treats testnet participation as a binding contract for mainnet equity.', 'Lets urgency substitute for analysis, converting pressure directly into action. The numbers on the screen are the only feedback that matters here.', 'A sharp initial spike of dread, resolving into paralysis — that keeps resurfacing in quiet moments for days afterward.', 0.58, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('b92f6dd1-334d-45d8-8669-65881f8a4aa4', 'b112d083-8faa-403a-b4e4-3a46c07647d9', '3ea1340d-ce39-453d-a433-b89713a2216f', 'Faced with this, this person reacts to the headline before confirming it, then scrambles to justify the trade after, and true to form takes the crowd''s confidence as a substitute for its own analysis.', 'Acts on the strongest immediate impulse and treats hesitation as its own kind of risk. The numbers on the screen are the only feedback that matters here.', 'A flash of heat that cools almost immediately, resolving into appeasement — that fades within the hour once the decision is locked in.', 0.58, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
('42a38512-ed5a-4242-ae68-6a3064b2737c', 'c9efcfad-6217-4b40-a6df-39ba6f5fbe5e', '55b4b68e-8f95-4365-9509-aecebf6cb4b8', 'Faced with this, this type runs the scenario through a checklist built in advance and follows wherever it points, and true to form holds their estimates with a certainty the track record does not support.', 'Builds an explicit decision matrix for a call most people would make on instinct, and defers to whichever option scores highest even if it feels wrong. This time the variable is money moving in real time.', 'Something closer to mild interest than alarm, resolving into relief capitulation — that leaves no discernible trace once the moment passes.', 0.91, 'c09637e6-6320-47d7-8d8f-6c374ac2b3fb'),
